./.planning/phases/04.4-filesystem-memory-tool-append-only-prefix-compaction-polish-/runs/v1-adoption-roundA/task06.jsonl:50:{"ts":"2026-04-27T03:52:10.168Z","type":"message_end","message":{"role":"toolResult","toolCallId":"call_32660e3baa794495a7425c96","toolName":"read","content":[{"type":"text","text":"{\"path\":\"/data/projects/emmy/emmy_serve/profile/schema.py\",\"binary\":false,\"lines\":\"a21c2f7c  \\\"\\\"\\\"Pydantic v2 schema for profile bundles (01-RESEARCH.md §2, §3, §4, §6).\\ne3b0c442  \\n89c0d04b  Every BaseModel gets `model_config = ConfigDict(extra='forbid', frozen=True)` —\\nc41dc306  this is the typo-safety + immutability floor for the keystone abstraction.\\ne3b0c442  \\n3da8783c  Field list copied from 01-RESEARCH.md §2 lines 502-585 (serving.yaml) and §3\\n3770ca8c  lines 617-679 (harness.yaml). Cross-field rules from §2 lines 598-609.\\ne3b0c442  \\n154d9477  D-03: schema is strict from v1 onward. No phase-scoped validation flags.\\nb6d267ef  \\\"\\\"\\\"\\na6284e6d  from __future__ import annotations\\ne3b0c442  \\n66ec0182  import re\\ncb450104  from typing import Any, Literal, Optional\\ne3b0c442  \\n6b5e59f7  from pydantic import BaseModel, ConfigDict, Field, field_validator, model_validator\\ne3b0c442  \\ne3b0c442  \\nc0404e26  # --- shared domain error class -------------------------------------------------\\ne3b0c442  \\ne3b0c442  \\nedeb57c3  class ProfileConfigError(Exception):\\n32615c37      \\\"\\\"\\\"Raised by loader layer when YAML fails schema or cross-field validation.\\ne3b0c442  \\na243fbaa      The loader wraps `pydantic.ValidationError` with dotted-path messages so the\\nb74e10a8      D-06 diagnostic bundle and `emmy profile validate` stderr have the shape\\n2387463c      established by the prior repo's `ConfigError` (01-PATTERNS.md Pattern A).\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\ne3b0c442  \\n9964edaf  # --- shared regex --------------------------------------------------------------\\ne3b0c442  \\n7a4e6aba  _SHA256 = re.compile(r\\\"^sha256:[0-9a-f]{64}$\\\")\\na89854b0  _SHA256_PLACEHOLDER = \\\"sha256:REPLACE_AT_FIRST_PULL\\\"\\ne3b0c442  \\ne3b0c442  \\n4295a894  # --- serving.yaml schema (01-RESEARCH.md §2) ----------------------------------\\ne3b0c442  \\ne3b0c442  \\ndb138dd2  class EngineConfig(BaseModel):\\n1f3e3c84      \\\"\\\"\\\"vLLM engine config — every field maps to a `vllm serve` CLI flag.\\ne3b0c442  \\n7b8c3c6c      Changes to any field require a container restart (PROFILE-03); the pydantic\\n7d9b5e7a      layer does NOT enforce restart ergonomics, the boot orchestrator does.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\ne3b0c442  \\n234d2fb2      # --- immutable identity ---\\na06fb0fb      model: str\\n6afc99ae      model_hf_id: str\\na1eaf8cb      served_model_name: str\\n7df72361      container_image: str\\n2b561740      container_image_digest: str\\n37a5b0f1      # Phase 4 v2 — optional per-profile `docker run --entrypoint` override.\\nc65fa69b      # NGC images carry `/opt/nvidia/nvidia_entrypoint.sh` which just `exec`s the\\n44fc7e29      # CMD, so the runner's default `vllm serve <flags>` CMD works as-is. Some\\nc6455e31      # upstream images (e.g. `vllm/vllm-openai:gemma4-*-arm64-cu130`) bake\\nde01bc75      # `[vllm serve]` as the ENTRYPOINT, which concatenates with the CMD and\\n53339079      # breaks the CLI parse. Setting this to an empty string clears the\\nab52ffbf      # entrypoint so the CMD runs as the full exec chain. Unset = use image's\\n97d6709d      # default ENTRYPOINT (backward-compat with Qwen v1/v2/v3/v3.1 profiles).\\n794c5d3f      container_entrypoint_override: Optional[str] = None\\ne3b0c442  \\n2512ba94      # --- context + memory ---\\ncd630a12      max_model_len: int = Field(gt=0)\\n9edc9d3e      gpu_memory_utilization: float = Field(gt=0.0, le=1.0)\\n90e772bc      kv_cache_dtype: Literal[\\\"auto\\\", \\\"fp8\\\", \\\"fp16\\\", \\\"bf16\\\"] = \\\"fp8\\\"\\ne05286b8      enable_prefix_caching: bool = True\\nb0c0b018      enable_chunked_prefill: bool = True\\nbb4acdd3      max_num_batched_tokens: int = Field(gt=0)\\n6301d40f      # Phase 4 — max_num_seqs (vLLM concurrent-sequence cap). Optional because\\n8aa4cd2c      # Qwen v1/v2/v3/v3.1 profiles don't ship it (vLLM default = 256 applies).\\nad6df23c      # Gemma 4 v1 pins it to 4 per NVIDIA Day-1 DGX Spark recipe and as a\\nf8c4bcdb      # defensive knob against vLLM Gemma4ToolParser bug #39392 (pad-token leak\\n010042e5      # under concurrent batch). See 04-RESEARCH.md §2 + PROFILE_NOTES.md.\\n703c4c48      max_num_seqs: Optional[int] = Field(default=None, gt=0)\\ne3b0c442  \\n9eb88509      # --- loader ---\\n8520db34      load_format: Literal[\\\"auto\\\", \\\"fastsafetensors\\\", \\\"safetensors\\\"] = \\\"fastsafetensors\\\"\\ne3b0c442  \\n81bf9721      # --- quantization ---\\n623571c9      quantization: Literal[\\\"fp8\\\", \\\"bf16\\\", \\\"auto\\\"] = \\\"fp8\\\"\\ne3b0c442  \\na9e5702e      # --- tool-call parser ---\\n372801e8      tool_call_parser: Optional[str] = None\\nfe417d22      # Phase 4 D-17 — reasoning_parser is an optional vLLM flag separate from\\n75b5d9c5      # tool_call_parser. Gemma 4 sets it to \\\"gemma4\\\" so the engine strips\\n582d2b75      # reasoning tokens from the SSE stream; Qwen profiles leave it unset and\\ncea60a80      # validate identically (backward-compat: Optional default None).\\naa4945b1      reasoning_parser: Optional[str] = None\\na0021908      enable_auto_tool_choice: bool = True\\ne3b0c442  \\n39b6e80a      # --- attention + backends ---\\nfa06c775      attention_backend: Optional[str] = None\\ne3b0c442  \\nc55eca53      # --- network / runtime ---\\ncc4e21de      host: str\\n66a49e9e      port: int = Field(gt=0, le=65535)\\ne3b0c442  \\na65c7034      @field_validator(\\\"container_image_digest\\\")\\nfe754ce9      @classmethod\\nbfe2129c      def _digest_shape(cls, v: str) -> str:\\ne666e334          if v == _SHA256_PLACEHOLDER:\\n4d2f0480              raise ValueError(\\nd7b7723d                  \\\"container_image_digest is still the template sentinel \\\"\\n018265f9                  f\\\"({_SHA256_PLACEHOLDER!r}) — run \\\"\\ne185008a                  \\\"`docker pull nvcr.io/nvidia/vllm:26.03.post1-py3` then \\\"\\n64221b68                  \\\"`docker inspect ... | jq -r '.[0].RepoDigests[0]'` and paste the real \\\"\\n0703cdf4                  \\\"digest (see 01-RESEARCH.md §12)\\\"\\n8ce8689b              )\\nbb3a19a1          if not _SHA256.match(v):\\n4d2f0480              raise ValueError(\\n9c607806                  f\\\"container_image_digest must match sha256:<64 hex>, got {v!r}\\\"\\n8ce8689b              )\\nbf268855          return v\\ne3b0c442  \\ne3b0c442  \\nd037fc9f  class SamplingDefaults(BaseModel):\\n880ee084      \\\"\\\"\\\"Prior-sampling settings; harness per-tool sampling overrides these.\\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\nac4b040d      temperature: float = Field(ge=0.0, le=2.0)\\n099da625      top_p: float = Field(gt=0.0, le=1.0)\\n56619f0a      top_k: int = Field(gt=0)\\n308d10c3      repetition_penalty: float = Field(gt=0.0)\\nfc71a203      max_tokens: int = Field(gt=0)\\n99200e89      stop: list[str] = []\\ne3b0c442  \\ne3b0c442  \\nbae9e110  class GuidedDecoding(BaseModel):\\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n4d044019      default_backend: Literal[\\\"xgrammar\\\", \\\"outlines\\\", \\\"guidance\\\"]\\ne3b0c442  \\ne3b0c442  \\n43550892  class Quirks(BaseModel):\\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n8ad9d192      strip_thinking_tags: bool\\n3c483fdb      promote_reasoning_to_content: bool\\n8033dd1b      buffer_tool_streams: bool\\ne3b0c442  \\ne3b0c442  \\n15c07d3e  class EnvVars(BaseModel):\\n4ea3a737      \\\"\\\"\\\"Environment variables set on the vLLM container.\\ne3b0c442  \\n4c454d09      Cross-field policy (01-RESEARCH.md §2 lines 607-609):\\n38974ac8        - VLLM_NO_USAGE_STATS must equal \\\"1\\\" (SERVE-09 / D-12 layer c)\\nbeaa8761        - HF_HUB_OFFLINE must equal \\\"1\\\" (REPRO-04 / D-12 layer d)\\ne3b0c442  \\n7b8a01af      These are correctness requirements, not defaults — a profile that weakens\\n980e35ed      either is rejected at validate time.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n24703f53      VLLM_NO_USAGE_STATS: str\\n126e9c95      DO_NOT_TRACK: str\\n9162ef5b      VLLM_LOAD_FORMAT: str\\nd833976b      VLLM_FLASHINFER_MOE_BACKEND: str\\n5f57a765      VLLM_DISABLE_COMPILE_CACHE: str\\nc6d65e10      HF_HUB_OFFLINE: str\\ncc58b4f1      TRANSFORMERS_OFFLINE: str\\ne3b0c442  \\n4c354ecd      @model_validator(mode=\\\"after\\\")\\nfcb2e380      def _airgap_policy(self) -> \\\"EnvVars\\\":\\nbd0c4de6          if self.VLLM_NO_USAGE_STATS != \\\"1\\\":\\n4d2f0480              raise ValueError(\\nd982a93f                  'env.VLLM_NO_USAGE_STATS must equal \\\"1\\\" (SERVE-09, D-12 layer c)'\\n8ce8689b              )\\nffef7b41          if self.HF_HUB_OFFLINE != \\\"1\\\":\\n4d2f0480              raise ValueError(\\n0a5949ee                  'env.HF_HUB_OFFLINE must equal \\\"1\\\" (REPRO-04, D-12 layer d)'\\n8ce8689b              )\\ncd9fb1b4          return self\\ne3b0c442  \\ne3b0c442  \\n2ea27240  class ServingConfig(BaseModel):\\nb4a7be42      \\\"\\\"\\\"Root of serving.yaml — one pydantic call validates the entire file.\\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n8c09d781      engine: EngineConfig\\nf660c3e4      sampling_defaults: SamplingDefaults\\n517058c9      # speculative=None in Phase 1 per CONTEXT.md deferred list / D-16.\\n9027ad97      # Phase 6 will replace this with a SpeculativeConfig BaseModel.\\na84bab7c      speculative: Optional[dict[str, Any]] = None\\ne91412ff   