fileConfigError(Exception):\\n32615c37      \\\"\\\"\\\"Raised by loader layer when YAML fails schema or cross-field validation.\\ne3b0c442  \\na243fbaa      The loader wraps `pydantic.ValidationError` with dotted-path messages so the\\nb74e10a8      D-06 diagnostic bundle and `emmy profile validate` stderr have the shape\\n2387463c      established by the prior repo's `ConfigError` (01-PATTERNS.md Pattern A).\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\ne3b0c442  \\n9964edaf  # --- shared regex --------------------------------------------------------------\\ne3b0c442  \\n7a4e6aba  _SHA256 = re.compile(r\\\"^sha256:[0-9a-f]{64}$\\\")\\na89854b0  _SHA256_PLACEHOLDER = \\\"sha256:REPLACE_AT_FIRST_PULL\\\"\\ne3b0c442  \\ne3b0c442  \\n4295a894  # --- serving.yaml schema (01-RESEARCH.md §2) ----------------------------------\\ne3b0c442  \\ne3b0c442  \\ndb138dd2  class EngineConfig(BaseModel):\\n1f3e3c84      \\\"\\\"\\\"vLLM engine config — every field maps to a `vllm serve` CLI flag.\\ne3b0c442  \\n7b8c3c6c      Changes to any field require a container restart (PROFILE-03); the pydantic\\n7d9b5e7a      layer does NOT enforce restart ergonomics, the boot orchestrator does.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\ne3b0c442  \\n234d2fb2      # --- immutable identity ---\\na06fb0fb      model: str\\n6afc99ae      model_hf_id: str\\na1eaf8cb      served_model_name: str\\n7df72361      container_image: str\\n2b561740      container_image_digest: str\\n37a5b0f1      # Phase 4 v2 — optional per-profile `docker run --entrypoint` override.\\nc65fa69b      # NGC images carry `/opt/nvidia/nvidia_entrypoint.sh` which just `exec`s the\\n44fc7e29      # CMD, so the runner's default `vllm serve <flags>` CMD works as-is. Some\\nc6455e31      # upstream images (e.g. `vllm/vllm-openai:gemma4-*-arm64-cu130`) bake\\nde01bc75      # `[vllm serve]` as the ENTRYPOINT, which concatenates with the CMD and\\n53339079      # breaks the CLI parse. Setting this to an empty string clears the\\nab52ffbf      # entrypoint so the CMD runs as the full exec chain. Unset = use image's\\n97d6709d      # default ENTRYPOINT (backward-compat with Qwen v1/v2/v3/v3.1 profiles).\\n794c5d3f      container_entrypoint_override: Optional[str] = None\\ne3b0c442  \\n2512ba94      # --- context + memory ---\\ncd630a12      max_model_len: int = Field(gt=0)\\n9edc9d3e      gpu_memory_utilization: float = Field(gt=0.0, le=1.0)\\n90e772bc      kv_cache_dtype: Literal[\\\"auto\\\", \\\"fp8\\\", \\\"fp16\\\", \\\"bf16\\\"] = \\\"fp8\\\"\\ne05286b8      enable_prefix_caching: bool = True\\nb0c0b018      enable_chunked_prefill: bool = True\\nbb4acdd3      max_num_batched_tokens: int = Field(gt=0)\\n6301d40f      # Phase 4 — max_num_seqs (vLLM concurrent-sequence cap). Optional because\\n8aa4cd2c      # Qwen v1/v2/v3/v3.1 profiles don't ship it (vLLM default = 256 applies).\\nad6df23c      # Gemma 4 v1 pins it to 4 per NVIDIA Day-1 DGX Spark recipe and as a\\nf8c4bcdb      # defensive knob against vLLM Gemma4ToolParser bug #39392 (pad-token leak\\n010042e5      # under concurrent batch). See 04-RESEARCH.md §2 + PROFILE_NOTES.md.\\n703c4c48      max_num_seqs: Optional[int] = Field(default=None, gt=0)\\ne3b0c442  \\n9eb88509      # --- loader ---\\n8520db34      load_format: Literal[\\\"auto\\\", \\\"fastsafetensors\\\", \\\"safetensors\\\"] = \\\"fastsafetensors\\\"\\ne3b0c442  \\n81bf9721      # --- quantization ---\\n623571c9      quantization: Literal[\\\"fp8\\\", \\\"bf16\\\", \\\"auto\\\"] = \\\"fp8\\\"\\ne3b0c442  \\na9e5702e      # --- tool-call parser ---\\n372801e8      tool_call_parser: Optional[str] = None\\nfe417d22      # Phase 4 D-17 — reasoning_parser is an optional vLLM flag separate from\\n75b5d9c5      # tool_call_parser. Gemma 4 sets it to \\\"gemma4\\\" so the engine strips\\n582d2b75      # reasoning tokens from the SSE stream; Qwen profiles leave it unset and\\ncea60a80      # validate identically (backward-compat: Optional default None).\\naa4945b1      reasoning_parser: Optional[str] = None\\na0021908      enable_auto_tool_choice: bool = True\\ne3b0c442  \\n39b6e80a      # --- attention + backends ---\\nfa06c775      attention_backend: Optional[str] = None\\ne3b0c442  \\nc55eca53      # --- network / runtime ---\\ncc4e21de      host: str\\n66a49e9e      port: int = Field(gt=0, le=65535)\\ne3b0c442  \\na65c7034      @field_validator(\\\"container_image_digest\\\")\\nfe754ce9      @classmethod\\nbfe2129c      def _digest_shape(cls, v: str) -> str:\\ne666e334          if v == _SHA256_PLACEHOLDER:\\n4d2f0480              raise ValueError(\\nd7b7723d                  \\\"container_image_digest is still the template sentinel \\\"\\n018265f9                  f\\\"({_SHA256_PLACEHOLDER!r}) — run \\\"\\ne185008a                  \\\"`docker pull nvcr.io/nvidia/vllm:26.03.post1-py3` then \\\"\\n64221b68                  \\\"`docker inspect ... | jq -r '.[0].RepoDigests[0]'` and paste the real \\\"\\n0703cdf4                  \\\"digest (see 01-RESEARCH.md §12)\\\"\\n8ce8689b              )\\nbb3a19a1          if not _SHA256.match(v):\\n4d2f0480              raise ValueError(\\n9c607806                  f\\\"container_image_digest must match sha256:<64 hex>, got {v!r}\\\"\\n8ce8689b              )\\nbf268855          return v\\ne3b0c442  \\ne3b0c442  \\nd037fc9f  class SamplingDefaults(BaseModel):\\n880ee084      \\\"\\\"\\\"Prior-sampling settings; harness per-tool sampling overrides these.\\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\nac4b040d      temperature: float = Field(ge=0.0, le=2.0)\\n099da625      top_p: float = Field(gt=0.0, le=1.0)\\n56619f0a      top_k: int = Field(gt=0)\\n308d10c3      repetition_penalty: float = Field(gt=0.0)\\nfc71a203      max_tokens: int = Field(gt=0)\\n99200e89      stop: list[str] = []\\ne3b0c442  \\ne3b0c442  \\nbae9e110  class GuidedDecoding(BaseModel):\\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n4d044019      default_backend: Literal[\\\"xgrammar\\\", \\\"outlines\\\", \\\"guidance\\\"]\\ne3b0c442  \\ne3b0c442  \\n43550892  class Quirks(BaseModel):\\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n8ad9d192      strip_thinking_tags: bool\\n3c483fdb      promote_reasoning_to_content: bool\\n8033dd1b      buffer_tool_streams: bool\\ne3b0c442  \\ne3b0c442  \\n15c07d3e  class EnvVars(BaseModel):\\n4ea3a737      \\\"\\\"\\\"Environment variables set on the vLLM container.\\ne3b0c442  \\n4c454d09      Cross-field policy (01-RESEARCH.md §2 lines 607-609):\\n38974ac8        - VLLM_NO_USAGE_STATS must equal \\\"1\\\" (SERVE-09 / D-12 layer c)\\nbeaa8761        - HF_HUB_OFFLINE must equal \\\"1\\\" (REPRO-04 / D-12 layer d)\\ne3b0c442  \\n7b8a01af      These are correctness requirements, not defaults — a profile that weakens\\n980e35ed      either is rejected at validate time.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n24703f53      VLLM_NO_USAGE_STATS: str\\n126e9c95      DO_NOT_TRACK: str\\n9162ef5b      VLLM_LOAD_FORMAT: str\\nd833976b      VLLM_FLASHINFER_MOE_BACKEND: str\\n5f57a765      VLLM_DISABLE_COMPILE_CACHE: str\\nc6d65e10      HF_HUB_OFFLINE: str\\ncc58b4f1      TRANSFORMERS_OFFLINE: str\\ne3b0c442  \\n4c354ecd      @model_validator(mode=\\\"after\\\")\\nfcb2e380      def _airgap_policy(self) -> \\\"EnvVars\\\":\\nbd0c4de6          if self.VLLM_NO_USAGE_STATS != \\\"1\\\":\\n4d2f0480              raise ValueError(\\nd982a93f                  'env.VLLM_NO_USAGE_STATS must equal \\\"1\\\" (SERVE-09, D-12 layer c)'\\n8ce8689b              )\\nffef7b41          if self.HF_HUB_OFFLINE != \\\"1\\\":\\n4d2f0480              raise ValueError(\\n0a5949ee                  'env.HF_HUB_OFFLINE must equal \\\"1\\\" (REPRO-04, D-12 layer d)'\\n8ce8689b              )\\ncd9fb1b4          return self\\ne3b0c442  \\ne3b0c442  \\n2ea27240  class ServingConfig(BaseModel):\\nb4a7be42      \\\"\\\"\\\"Root of serving.yaml — one pydantic call validates the entire file.\\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n8c09d781      engine: EngineConfig\\nf660c3e4      sampling_defaults: SamplingDefaults\\n517058c9      # speculative=None in Phase 1 per CONTEXT.md deferred list / D-16.\\n9027ad97      # Phase 6 will replace this with a SpeculativeConfig BaseModel.\\na84bab7c      speculative: Optional[dict[str, Any]] = None\\ne91412ff      guided_decoding: GuidedDecoding\\ndfb8cadc      quirks: Quirks\\n77c66bd5      env: EnvVars\\ne3b0c442  \\ne3b0c442  \\n04f10a13  # --- harness.yaml schema (01-RESEARCH.md §3) ----------------------------------\\ne3b0c442  \\ne3b0c442  \\n7f08527b  class PromptsConfig(BaseModel):\\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\na01b6d65      system: str\\n4147825a      edit_format: Optional[str] = None\\n119db373      tool_descriptions: Optional[str] = None\\n4c7ffa93      use_system_role: bool\\n6441aacc      prepend_system_text: str\\ne3b0c442  \\ne3b0c442  \\nf268bc55  class CompactionConfig(BaseModel):\\nafd132ce      \\\"\\\"\\\"Per-profile auto-compaction policy (Phase 3 D-11..D-17).\\ne3b0c442  \\n21a389de      Shipped in v3 as the first profile to carry the block; v2 (and v1) validate\\n51f6e99e      without it (Optional[CompactionConfig] = None on ContextConfig). See\\n79c7ccc5      CONTEXT.md D-11..D-17 + ``packages/emmy-context/`` for the runtime that\\nbe2c3834      consumes this.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\nd5274f5c      soft_threshold_pct: float = Field(..., ge=0.0, le=1.0)\\n3c57f7ee      preserve_recent_turns: int = Field(..., ge=0)\\nc7eb9868      summarization_prompt_path: str = Field(..., min_length=1)\\n4e4ff67c      preserve_tool_results: Literal[\\\"error_only\\\", \\\"none\\\", \\\"all\\\"] = \\\"error_only\\\"\\ne3b0c442  \\ne3b0c442  \\n118a7c00  class MemoryConfig(BaseModel):\\n2e84d1a2      \\\"\\\"\\\"Per-profile filesystem-memory tool config (Phase 04.4 plan 03).\\ne3b0c442  \\n878c7897      See `.planning/pre-phase/04.4-memory-compaction/MEMORY-TOOL-SPEC.md` §3.2\\n8666babb      for design + defaults rationale. The runtime tool lives at\\n66b35316      `packages/emmy-tools/src/memory/`; this schema is the only validated\\n1ff6bb3f      contract between profile bundles and that runtime.\\ne3b0c442  \\nf6d03ed0      Fields:\\n2abd17cf        - enabled: master switch. False → tool not registered; description omitted.\\n51c4f677        - project_root: relative-to-cwd dir for /memories/project/...; null = scope disabled.\\nca7287da        - global_root: ~-prefixed or absolute dir for /memories/global/...; null = scope disabled.\\n274f384e        - read_at_session_start: whether the instinct prompt fires at session boot.\\nc7a03703        - max_file_bytes: per-file write cap (deliberate; forces consolidation).\\n455e78a5        - max_total_bytes: per-scope cap (deliberate; prevents unbounded growth).\\na10cf22f        - blocked_extensions: belt-and-braces secret-accumulation guard.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\nb07e98ee      enabled: bool = True\\n955e1388      project_root: Optional[str] = \\\".emmy/notes\\\"\\n74739a9e      global_root: Optional[str] = \\\"~/.emmy/memory\\\"\\n76226ad8      read_at_session_start: bool = True\\n8cc43703      max_file_bytes: int = Field(default=65536, gt=0)\\nf5ebd3e0      max_total_bytes: int = Field(default=10_485_760, gt=0)\\nd213150b      blocked_extensions: list[str] = Field(default_factory=lambda: [\\\".env\\\", \\\".key\\\", \\\".pem\\\"])\\ne3b0c442  \\n4c354ecd      @model_validator(mode=\\\"after\\\")\\nce5d51a8      def _scope_cap_at_least_file_cap(self) -> \\\"MemoryConfig\\\":\\ne86a04d6          if self.max_total_bytes < self.max_file_bytes:\\n4d2f0480              raise ValueError(\\n6bf23ef7                  f\\\"max_total_bytes ({self.max_total_bytes}) must be >= max_file_bytes \\\"\\n88462028                  f\\\"({self.max_file_bytes}) — a single max-size file must fit in the scope\\\"\\n8ce8689b              )\\ncd9fb1b4          return self\\ne3b0c442  \\ne3b0c442  \\n08e81fcd  class ContextConfig(BaseModel):\\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n454fa8dd      max_input_tokens: int = Field(gt=0)\\ne7df252c      include_repo_map: bool\\n4d3f0176      repo_map_max_tokens: int = Field(ge=0)\\n8ce36961      default_pruning: Literal[\\\"head_tail\\\", \\\"recency_window\\\", \\\"importance\\\"]\\n80c42f5c      # D-15 — optional per-profile compaction policy. v1/v2 validate without it;\\ndbffad80      # v3 ships the block. Presence is opt-in; absence means compaction disabled.\\n8c5f32e2      compaction: Optional[CompactionConfig] = None\\n1b2299e5      # Phase 04.4 plan 03 — optional per-profile memory tool config. Profiles\\n11965d79      # without the block validate (None); the four shipped profiles (v3.1, v1.1,\\ne13a14e1      # v2, v1.1) ship the block. Runtime in packages/emmy-tools/src/memory/.\\n56e86387      memory: Optional[MemoryConfig] = None\\ne3b0c442  \\ne3b0c442  \\nd2a17a0c  class GrammarConfig(BaseModel):\\ne583788e      \\\"\\\"\\\"Nested grammar config (Phase-2 D-11 lock — see CONTEXT.md §D-11).\\ne3b0c442  \\n6ac85ec4      The pre-revision shape was a bare `str` (path only). Phase 2 locks a nested\\n79fbe761      `{path, mode}` shape so the harness can carry the reactive/disabled knob\\nd082642f      alongside the grammar file. The `reactive` mode is Phase 2's production path\\na2c945f7      per CLAUDE.md Pitfall #6 (\\\"grammar is a correctness backstop, not a quality\\ne903eb78      lever\\\"); the `disabled` mode is reserved for the SC-3 no-grammar baseline\\nd0b9d825      (Plan 02-08, D-14).\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n163d5089      path: str\\nc3129d63      mode: Literal[\\\"reactive\\\", \\\"disabled\\\"] = \\\"reactive\\\"\\ne3b0c442  \\ne3b0c442  \\n701bb811  class WebFetchConfig(BaseModel):\\nb16efba7      \\\"\\\"\\\"web_fetch allowlist policy (Phase 3 D-26..D-28 + Phase 3.1 D-35).\\ne3b0c442  \\n2fc927e8      Shipped in v3; v1/v2 validate without it (Optional[WebFetchConfig] = None on\\n46d48547      ToolsConfig). Hostname-EXACT matching enforced at runtime by\\n1a0adfec      ``packages/emmy-tools/src/web-fetch-allowlist.ts`` (Plan 03-06). An empty\\n414dacea      allowlist means default-deny (all non-loopback hosts blocked).\\ne3b0c442  \\n8913b805      Plan 03.1-02 D-35 — ``search_bypass_ttl_ms`` extends enforcement: URLs\\n6da1c5b0      returned by a recent ``web_search`` call are fetchable without allowlist\\na1e06294      entry for ``search_bypass_ttl_ms`` milliseconds (default 300000 = 5 min).\\n145a4ff6      0 disables the bypass entirely. Exact URL match (NOT hostname substring)\\nbf709989      per T-03.1-02-02 SSRF mitigation.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\ne15fd584      allowlist: list[str] = Field(default_factory=list)\\na750da12      # D-35 — Plan 03.1-02 returned-URL bypass TTL (ms). 0 = disabled.\\nea288a97      search_bypass_ttl_ms: int = Field(default=300000, ge=0)\\ne3b0c442  \\ne3b0c442  \\n0874abaf  class WebSearchConfig(BaseModel):\\nf8448879      \\\"\\\"\\\"web_search tool config (Phase 3.1 D-34).\\ne3b0c442  \\n1bd56539      Shipped in v3.1; v1/v2/v3 validate without it (Optional[WebSearchConfig]\\n03287fc7      = None on ToolsConfig). SearxNG JSON API at ``base_url`` is the only\\n2c825195      permitted target (loopback-only). Runtime enforcement in\\n3677ad1e      ``packages/emmy-tools/src/web-search.ts``.\\ne3b0c442  \\n509b5d87      Knobs:\\nd038fab2        - enabled: master switch. False or None → tool not registered.\\nd859aa2a        - base_url: SearxNG endpoint; MUST be loopback-bound for T-03.1-02\\n16ac59ea          trust-boundary containment.\\n983dec21        - max_results_default: returned to the model when it omits max_results.\\n63fc18da        - rate_limit_per_turn: T-03.1-02-03 DoS guard; hard-cap per agent turn.\\n8f0aab1a        - timeout_ms: per-call HTTP timeout; keeps agent loop responsive.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\nf9670d04      enabled: bool = False\\n8ca814bf      base_url: str = \\\"http://127.0.0.1:8888\\\"\\n55bf5199      max_results_default: int = Field(default=10, ge=1, le=50)\\ne3921380      rate_limit_per_turn: int = Field(default=10, ge=1, le=100)\\ne1af5f60      timeout_ms: int = Field(default=10000, ge=1000, le=60000)\\ne3b0c442  \\ne3b0c442  \\nbf987e4c  class ToolsConfig(BaseModel):\\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n041e4db0      format: Literal[\\\"openai\\\", \\\"hermes\\\"]\\n4b4a7ab3      schemas: Optional[str] = None\\n4dc4b8cc      # Phase-2 D-11: nested GrammarConfig. None = no grammar configured (Phase 1\\nf6bcc373      # v1 default; the reactive-retry path fails loud with `no_grammar_configured`\\n4c8c5652      # when a model emits an unparseable tool-call).\\n7a893a77      grammar: Optional[GrammarConfig] = None\\nd9075750      per_tool_sampling: dict[str, Any] = {}\\na109027b      # D-26..D-28 — per-profile web_fetch allowlist. v1/v2 validate without it;\\ndbde8e96      # v3 ships the block. Runtime enforcement in @emmy/tools/web-fetch-allowlist.\\n3ec2d322      web_fetch: Optional[WebFetchConfig] = None\\n1a66e5b8      # Phase 3.1 D-34 — per-profile web_search config. v1/v2/v3 validate without\\n5c083974      # it; v3.1 ships the block. Runtime enforcement in @emmy/tools/web-search.\\n2660a8db      web_search: Optional[WebSearchConfig] = None\\ne3b0c442  \\ne3b0c442  \\nd6ebbc3d  class AgentLoopConfig(BaseModel):\\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n753b96c0      max_iterations: int = Field(gt=0)\\n6785f476      retry_on_unparseable_tool_call: int = Field(ge=0)\\ndc50d504      retry_on_empty_response: int = Field(ge=0)\\n4c289129      self_correction: Literal[\\\"enabled\\\", \\\"disabled\\\"]\\ne3b0c442  \\ne3b0c442  \\nbc785df7  class VariantSamplingDefaults(BaseModel):\\n9ba77291      \\\"\\\"\\\"Phase 4 HARNESS-08 — variant-level sampling_defaults.\\ne3b0c442  \\nc1054b70      Sibling variants under the same profile share a byte-identical serving.yaml\\n88bb224d      (engine byte-identity invariant, CI-enforced in\\n91b6a964      tests/unit/test_variant_engine_byte_identity.py). Per-turn sampling\\n00d61aa3      overrides therefore live in harness.yaml and are applied by\\n10dbeaf5      packages/emmy-provider/src/before-request-hook.ts at wire time.\\ne3b0c442  \\n3610bc7c      All fields are OPTIONAL because a variant may only diverge on a subset\\n5b0a24dc      (e.g. v3.1-default overrides nothing and v3.1-reason overrides only\\n3a1acad0      temperature + top_p). Absent fields fall through to the base serving.yaml\\nf24a327f      sampling_defaults.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n532c3103      temperature: Optional[float] = Field(default=None, ge=0.0, le=2.0)\\n0100c925      top_p: Optional[float] = Field(default=None, gt=0.0, le=1.0)\\n0062049c      top_k: Optional[int] = Field(default=None, gt=0)\\n15ab801d      max_tokens: Optional[int] = Field(default=None, gt=0)\\nbc00fe79      repetition_penalty: Optional[float] = Field(default=None, gt=0.0)\\ne3b0c442  \\ne3b0c442  \\n8e361763  class PersonaConfig(BaseModel):\\n936fccf3      \\\"\\\"\\\"One persona under harness.yaml `subagents.personas.<name>` (Phase 04.5 plan 02).\\ne3b0c442  \\neac7af37      See `.planning/pre-phase/04.5-subagents/INTEGRATION-SKETCH.md` § persona schema\\n2e661224      for design rationale; runtime in `packages/emmy-tools/src/subagent/`.\\ne3b0c442  \\nf6d03ed0      Fields:\\n907329c0        - description: surfaced on the parent's tool description for `subagent_type` enum.\\n82dfb704        - pattern: \\\"lean\\\" reuses parent services; \\\"persona\\\" loads a persona_dir.\\n94f20c45        - persona_dir: REQUIRED when pattern == \\\"persona\\\"; relative to bundle root.\\n4562b3a4        - tool_allowlist: subset of parent tools the child may call (V3).\\nf76a199c        - model_override: v1 single-model only — must be null for both patterns.\\nc7c36306        - max_turns: child agent-loop hard cap.\\n9c6207ea        - persist_transcript: write child JSONL alongside parent's session dir.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\nbf454182      description: str\\nb685ac17      pattern: Literal[\\\"lean\\\", \\\"persona\\\"]\\n76759860      persona_dir: Optional[str] = None\\nd614daca      tool_allowlist: list[str] = []\\nb945291d      model_override: Optional[str] = None\\na9bcbbfa      max_turns: int = Field(default=10, gt=0)\\nae612d19      persist_transcript: bool = False\\ne3b0c442  \\n4c354ecd      @model_validator(mode=\\\"after\\\")\\n0bfb54c2      def _persona_pattern_needs_dir(self) -> \\\"PersonaConfig\\\":\\n12ca6826          if self.pattern == \\\"persona\\\" and not self.persona_dir:\\n3b78083f              raise ValueError(\\\"pattern='persona' requires persona_dir\\\")\\n5c45907b          if self.pattern == \\\"lean\\\" and self.persona_dir:\\nad533ff2              raise ValueError(\\\"pattern='lean' must not declare persona_dir\\\")\\n41efc909          if self.model_override is not None:\\n4d2f0480              raise ValueError(\\n78877bcf                  \\\"model_override must be null in v1 (single-model only); \\\"\\n9359900b                  \\\"cross-model dispatch deferred per 04.5 CONTEXT.md\\\"\\n8ce8689b              )\\ncd9fb1b4          return self\\ne3b0c442  \\ne3b0c442  \\n9fd18e69  class SubagentsConfig(BaseModel):\\nc0c688fe      \\\"\\\"\\\"Per-profile sub-agent dispatch config (Phase 04.5 plan 02).\\ne3b0c442  \\n289cbdc7      See `.planning/pre-phase/04.5-subagents/INTEGRATION-SKETCH.md` for design\\nb8017b27      rationale + LOCKED defaults. Runtime in `packages/emmy-tools/src/subagent/`.\\nae09dddd      Profile bundles without a subagents block validate (None at HarnessConfig);\\n1bc33a85      the four shipped profiles (v3.1, v1.1, v2, v1.1) all ship the block.\\ne3b0c442  \\nf6d03ed0      Fields:\\n102a6844        - enabled: master switch; false → Agent tool not registered.\\nab1d1a82        - max_concurrent: hardware cap on simultaneous children (LOCKED 2 on Spark).\\ne4e50c0f        - long_context_serialize_threshold_tokens: parent input above which\\nfd295738          children serialize instead of running concurrently (40K LOCKED per\\n63fb65d3          04.5 CONTEXT.md V6 design).\\n4622d3f7        - default_memory_scope: project | global | none — children's memory scope.\\n3b804226        - personas: persona name → PersonaConfig.\\nc7fecba7      \\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\nb07e98ee      enabled: bool = True\\n25b23cef      max_concurrent: int = Field(default=2, gt=0)\\n6039ac90      long_context_serialize_threshold_tokens: int = Field(default=40000, gt=0)\\nceb62f55      default_memory_scope: Literal[\\\"project\\\", \\\"global\\\", \\\"none\\\"] = \\\"project\\\"\\ne8ffb11d      personas: dict[str, PersonaConfig] = Field(default_factory=dict)\\ne3b0c442  \\ne3b0c442  \\n750a56cd  class HarnessConfig(BaseModel):\\nb8301838      \\\"\\\"\\\"Root of harness.yaml — Phase-2 placeholder values allowed as long as they type-check.\\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n5bbf5fc9      prompts: PromptsConfig\\ncf441e6f      context: ContextConfig\\nfbd57324      tools: ToolsConfig\\n4919fa46      agent_loop: AgentLoopConfig\\n03bf8b7b      advanced_settings_whitelist: list[str] = []\\nebc73b2b      # Phase 4 HARNESS-08 (D-10 variant harness divergence) — optional variant-\\nb565c331      # level sampling_defaults. Applied per-turn by before_provider_request;\\nedd8bfbd      # sibling variants of the same profile share a byte-identical serving.yaml\\nf16344a2      # but may declare different harness-side sampling_defaults. v1/v2/v3/v3.1\\n90b75ee4      # base bundles validate without this block (None).\\n3e9da080      sampling_defaults: Optional[VariantSamplingDefaults] = None\\n66042a9a      # Phase 4 HARNESS-08 — optional variant-level chat_template_kwargs (e.g.\\n74866cee      # {\\\"enable_thinking\\\": true} on v3.1-reason). Merged into the outgoing chat\\n9043a859      # request's chat_template_kwargs by before_provider_request. Values are\\ne62e578b      # free-form because upstream chat templates accept arbitrary keys; the\\n2b6cee4d      # \\\"no-model-conditionals\\\" D-19 audit ensures we don't branch on these\\n966ae0bb      # values in code.\\n6701e112      chat_template_kwargs: Optional[dict[str, Any]] = None\\ncdb8b29e      # Phase 04.5 plan 02 — optional per-profile sub-agent dispatch config.\\n2b54772e      # Profiles without the block validate (None); the four shipped profiles\\n3ac8b969      # (v3.1, v1.1, v2, v1.1) ship the block. Runtime in\\n778f4e7d      # packages/emmy-tools/src/subagent/.\\n8d70549e      subagents: Optional[SubagentsConfig] = None\\ne3b0c442  \\ne3b0c442  \\n869afdbf  # --- profile.yaml manifest (01-RESEARCH.md §4) --------------------------------\\ne3b0c442  \\ne3b0c442  \\n3ba94690  class CommunitySource(BaseModel):\\n89e52ef5      \\\"\\\"\\\"One entry in profile.yaml.profile.community_sources (PROFILE-05).\\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n8264e576      title: str\\nd7760acd      url: str\\n609855a1      retrieved: str  # YYYY-MM-DD\\ne3b0c442  \\ne3b0c442  \\n23979a4c  class ProfileManifest(BaseModel):\\nbf9a01bd      \\\"\\\"\\\"Inner `profile:` block of profile.yaml.\\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\ne3b0c442  \\nea7fcb53      id: str\\nc932e5b4      version: str\\n633eed6c      family: str\\n7dedce2e      base_model: str\\nbf454182      description: str\\n6d70163f      created: str\\n9d7f9a23      hash: str\\n6375264f      hash_algorithm: Literal[\\\"sha256\\\"] = \\\"sha256\\\"\\n85aade18      hash_manifest_version: int = 1\\n2e3a29c7      tags: list[str] = []\\n9db1b0de      community_sources: list[CommunitySource] = []\\ne3b0c442  \\n2c73e1f3      @field_validator(\\\"hash\\\")\\nfe754ce9      @classmethod\\n91b8c27b      def _hash_shape(cls, v: str) -> str:\\nbb3a19a1          if not _SHA256.match(v):\\n4d2f0480              raise ValueError(\\n5c1848f1                  f\\\"hash must match sha256:<64 hex>, got {v!r} \\\"\\n372ac990                  \\\"(run `emmy profile hash <path> --write` to compute)\\\"\\n8ce8689b              )\\nbf268855          return v\\ne3b0c442  \\ne3b0c442  \\n3c7b1e15  class ProfileYaml(BaseModel):\\n0d45a915      \\\"\\\"\\\"Root of profile.yaml — wraps the manifest under a single `profile:` key.\\\"\\\"\\\"\\ne3b0c442  \\nf3bcdd66      model_config = ConfigDict(extra=\\\"forbid\\\", frozen=True)\\n32c68eeb      profile: ProfileManifest\\ne3b0c442  \\ne3b0c442  \\n660ff8d7  __all__ = [\\n7a61762a      \\\"ProfileConfigError\\\",\\n38c87599      \\\"EngineConfig\\\",\\n79a5fa81      \\\"SamplingDefaults\\\",\\n27ae5cba      \\\"GuidedDecoding\\\",\\n7700d3d9      \\\"Quirks\\\",\\n45cd20cc      \\\"EnvVars\\\",\\n4ab0ae6f      \\\"ServingConfig\\\",\\na08360e7      \\\"PromptsConfig\\\",\\n97528dd7      \\\"CompactionConfig\\\",\\n6ba58fc5      \\\"MemoryConfig\\\",\\nb6fb5ec2      \\\"ContextConfig\\\",\\n01c949ec      \\\"GrammarConfig\\\",\\n37435a93      \\\"WebFetchConfig\\\",\\n4ac17050      \\\"WebSearchConfig\\\",\\nb190d0d0      \\\"ToolsConfig\\\",\\n7ec26e0f      \\\"AgentLoopConfig\\\",\\nc40ed1a7      \\\"HarnessConfig\\\",\\n3b84f69b      \\\"CommunitySource\\\",\\nd0f672c9      \\\"ProfileManifest\\\",\\nb5315cea      \\\"ProfileYaml\\\",\\ncfae0d42  ]\\n\",\"line_count\":542}"}],"details":{"path":"/data/projects/emmy/emmy_serve/profile/schema.py","binary":false,"lines":"a21c2f7c  \"\"\"Pydantic v2 schema for profile bundles (01-RESEARCH.md §2, §3, §4, §6).\ne3b0c442  \n89c0d04b  Every BaseModel gets `model_config = ConfigDict(extra='forbid', frozen=True)` —\nc41dc306  this is the typo-safety + immutability floor for the keystone abstraction.\ne3b0c442  \n3da8783c  Field list copied from 01-RESEARCH.md §2 lines 502-585 (serving.yaml) and §3\n3770ca8c  lines 617-679 (harness.yaml). Cross-field rules from §2 lines 598-609.\ne3b0c442  \n154d9477  D-03: schema is strict from v1 onward. No phase-scoped validation flags.\nb6d267ef  \"\"\"\na6284e6d  from __future__ import annotations\ne3b0c442  \n66ec0182  import re\ncb450104  from typing import Any, Literal, Optional\ne3b0c442  \n6b5e59f7  from pydantic import BaseModel, ConfigDict, Field, field_validator, model_validator\ne3b0c442  \ne3b0c442  \nc0404e26  # --- shared domain error class -------------------------------------------------\ne3b0c442  \ne3b0c442  \nedeb57c3  class ProfileConfigError(Exception):\n32615c37      \"\"\"Raised by loader layer when YAML fails schema or cross-field validation.\ne3b0c442  \na243fbaa      The loader wraps `pydantic.ValidationError` with dotted-path messages so the\nb74e10a8      D-06 diagnostic bundle and `emmy profile validate` stderr have the shape\n2387463c      established by the prior repo's `ConfigError` (01-PATTERNS.md Pattern A).\nc7fecba7      \"\"\"\ne3b0c442  \ne3b0c442  \n9964edaf  # --- shared regex --------------------------------------------------------------\ne3b0c442  \n7a4e6aba  _SHA256 = re.compile(r\"^sha256:[0-9a-f]{64}$\")\na89854b0  _SHA256_PLACEHOLDER = \"sha256:REPLACE_AT_FIRST_PULL\"\ne3b0c442  \ne3b0c442  \n4295a894  # --- serving.yaml schema (01-RESEARCH.md §2) ----------------------------------\ne3b0c442  \ne3b0c442  \ndb138dd2  class EngineConfig(BaseModel):\n1f3e3c84      \"\"\"vLLM engine config — every field maps to a `vllm serve` CLI flag.\ne3b0c442  \n7b8c3c6c      Changes to any field require a container restart (PROFILE-03); the pydantic\n7d9b5e7a      layer does NOT enforce restart ergonomics, the boot orchestrator does.\nc7fecba7      \"\"\"\ne3b0c442  \nf3bcdd66      model_config = ConfigDict(extra=\"forbid\", frozen=True)\ne3b0c442  \n234d2fb2      # --- immutable identity ---\na06fb0fb      model: str\n6afc99ae      model_hf_id: str\na1eaf8cb      served_model_name: str\n7df72361      container_image: str\n2b561740      container_image_digest: str\n37a5b0f1      # Phase 4 v2 — optional per-profile `docker run --entrypoint` override.\nc65fa69b      # NGC images carry `/opt/nvidia/nvidia_entrypoint.sh` which just `exec`s the\n44fc7e29      # CMD, so the runner's default `vllm serve <flags>` CMD works as-is. Some\nc6455e31      # upstream images (e.g. `vllm/vllm-openai:gemma4-*-arm64-cu130`) bake\nde01bc75      # `[vllm serve]` as the ENTRYPOINT, which concatenates with the CMD and\n53339079      # breaks the CLI parse. Setting this to an empty string clears the\nab52ffbf      # entrypoint so the CMD runs as the full exec chain. Unset = use image's\n97d6709d      # default ENTRYPOINT (backward-compat with Qwen v1/v2/v3/v3.1 profiles).\n794c5d3f      container_entrypoint_override: Optional[str] = None\ne3b0c442  \n2512ba94      # --- context + memory ---\ncd630a12      max_model_len: int = Field(gt=0)\n9edc9d3e      gpu_memory_utilization: float = Field(gt=0.0, le=1.0)\n90e772bc      kv_cache_dtype: Literal[\"auto\", \"fp8\", \"fp16\", \"bf16\"] = \"fp8\"\ne05286b8      enable_prefix_caching: bool = True\nb0c0b018      enable_chunked_prefill: bool = True\nbb4acdd3      max_num_batched_tokens: int = Field(gt=0)\n6301d40f      # Phase 4 — max_num_seqs (vLLM concurrent-sequence cap). Optional because\n8aa4cd2c      # Qwen v1/v2/v3/v3.1 profiles don't ship it (vLLM default = 256 applies).\nad6df23c      # Gemma 4 v1 pins it to 4 per NVIDIA Day-1 DGX Spark recipe and as a\nf8c4bcdb      # defensive knob against vLLM Gemma4ToolParser bug #39392 (pad-token leak\n010042e5      # under concurrent batch). See 04-RESEARCH.md §2 + PROFILE_NOTES.md.\n703c4c48      max_num_seqs: Optional[int] = Field(default=None, gt=0)\ne3b0c442  \n9eb88509      # --- loader ---\n8520db34      load_format: Literal[\"auto\", \"fastsafetensors\", \"safetensors\"] = \"fastsafetensors\"\ne3b0c442  \n81bf9721      # --- quantization ---\n623571c9      quantization: Literal[\"fp8\", \"bf16\", \"auto\"] = \"fp8\"\ne3b0c442  \na9e5702e      # --- tool-call parser ---\n372801e8      tool_call_parser: Optional[str] = None\nfe417d22      # Phase 4 D-17 — reasoning_parser is an optional vLLM flag separate from\n75b5d9c5      # tool_call_parser. Gemma 4 sets it to \"gemma4\" so the engine strips\n582d2b75      # reasoning tokens from the SSE stream; Qwen profiles leave it unset and\ncea60a80      # validate identically (backward-compat: Optional default None).\naa4945b1      reasoning_parser: Optional[str] = None\na0021908      enable_auto_tool_choice: bool = True\ne3b0c442  \n39b6e80a      # --- attention + backends ---\nfa06c775      attention_backend: Optional[str] = None\ne3b0c442  \nc55eca53      # --- network / runtime ---\ncc4e21de      host: str\n66a49e9e      port: int = Field(gt=0, le=65535)\ne3b0c442  \na65c7034      @field_validator(\"container_image_digest\")\nfe754ce9      @classmethod\nbfe2129c      def _digest_shape(cls, v: str) -> str:\ne666e334          if v == _SHA256_PLACEHOLDER:\n4d2f0480              raise ValueError(\nd7b7723d                  \"container_image_digest is still the template sentinel \"\n018265f9                  f\"({_SHA256_PLACEHOLDER!r}) — run \"\ne185008a                  \"`docker pull nvcr.io/nvidia/vllm:26.03.post1-py3` then \"\n64221b68                  \"`docker inspect ... | jq -r '.[0].RepoDigests[0]'` and paste the real \"\n0703cdf4                  \"digest (see 01-RESEARCH.md §12)\"\n8ce8689b              )\nbb3a19a1          if not _SHA256.match(v):\n4d2f0480              raise ValueError(\n9c607806                  f\"container_image_digest must match sha256:<64 hex>, got {v!r}\"\n8ce8689b              )\nbf268855          return v\ne3b0c442  \ne3b0c442  \nd037fc9f  class SamplingDefaults(BaseModel):\n880ee084      \"\"\"Prior-sampling settings; harness per-tool sampling overrides these.\"\"\"\ne3b0c442  \nf3bcdd66      model_config = ConfigDict(extra=\"forbid\", frozen=True)\nac4b040d      temperature: float = Field(ge=0.0, le=2.0)\n099da625      top_p: float = Field(gt=0.0, le=1.0)\n56619f0a      top_k: int = Field(gt=0)\n308d10c3      repetition_penalty: float = Field(gt=0.0)\nfc71a203      max_tokens: int = Field(gt=0)\n99200e89      stop: list[str] = []\ne3b0c442  \ne3b0c442  \nbae9e110  class GuidedDecoding(BaseModel):\nf3bcdd66      model_config = ConfigDict(extra=\"forbid\", frozen=True)\n4d044019      default_backend: Literal[\"xgrammar\", \"outlines\", \"guidance\"]\ne3b0c442  \ne3b0c442  \n43550892  class Quirks(BaseModel):\nf3bcdd66      model_config = ConfigDict(extra=\"forbid\", frozen=True)\n8ad9d192      strip_thinking_tags: bool\n3c483fdb      promote_reasoning_to_content: bool\n8033dd1b      buffer_tool_streams: bool\ne3b0c442  \ne3b0c442  \n15c07d3e  class EnvVars(BaseModel):\n4ea3a737      \"\"\"Environment variables set on the vLLM container.\ne3b0c442  \n4c454d09      Cross-field policy (01-RESEARCH.md §2 lines 607-609):\n38974ac8        - VLLM_NO_USAGE_STATS must equal \"1\" (SERVE-09 / D-12 layer c)\nbeaa8761        - HF_HUB_OFFLINE must equal \"1\" (REPRO-04 / D-12 layer d)\ne3b0c442  \n7b8a01af      These are correctness requirements, not defaults — a profile that weakens\n980e35ed      either is rejected at validate time.\nc7fecba7      \"\"\"\ne3b0c442  \nf3bcdd66      model_config = ConfigDict(extra=\"forbid\", frozen=True)\n24703f53      VLLM_NO_USAGE_STATS: str\n126e9c95      DO_NOT_TRACK: str\n9162ef5b      VLLM_LOAD_FORMAT: str\nd833976b      VLLM_FLASHINFER_MOE_BACKEND: str\n5f57a765      VLLM_DISABLE_COMPILE_CACHE: str\nc6d65e10      HF_HUB_OFFLINE: str\ncc58b4f1      TRANSFORMERS_OFFLINE: str\ne3b0c442  \n4c354ecd      @model_validator(mode=\"after\")\nfcb2e380      def _airgap_policy(self) -> \"EnvVars\":\nbd0c4de6          if self.VLLM_NO_USAGE_STATS != \"1\":\n4d2f0480              raise ValueError(\nd982a93f                  'env.VLLM_NO_USAGE_STATS must equal \"1\" (SERVE-09, D-12 layer c)'\n8ce8689b              )\nffef7b41          if self.HF_HUB_OFFLINE != \"1\":\n4d2f0480              raise ValueError(\n0a5949ee                  'env.HF_HUB_OFFLINE must equal \"1\" (REPRO-04, D-12 layer d)'\n8ce8689b              )\ncd9fb1b4          return self\ne3b0c442  \ne3b0c442  \n2ea27240  class ServingConfig(BaseModel):\nb4a7be42      \"\"\"Root of serving.yaml — one pydantic call validates the entire file.\"\"\"\ne3b0c442  \nf3bcdd66      model_config = ConfigDict(extra=\"forbid\", frozen=True)\n8c09d781      engine: EngineConfig\nf660c3e4      sampling_defaults: SamplingDefaults\n517058c9      # speculative=None in Phase 1 per CONTEXT.md deferred list / D-16.\n9027ad97      # Phase 6 will replace this with a SpeculativeConfig BaseModel.\na84bab7c      speculative: Optional[dict[str, Any]] = None\ne91412ff      guided_decoding: GuidedDecoding\ndfb8cadc      quirks: Quirks\n77c66bd5      env: EnvVars\ne3b0c442  \ne3b0c442  \n04f10a13  # --- harness.yaml schema (01-RESEARCH.md §3) ----------------------------------\ne3b0c442  \ne3b0c442  \n7f08527b  class PromptsConfig(BaseModel):\nf3bcdd66      model_config = ConfigDict(extra=\"forbid\", frozen=True)\na01b6d65      system: str\n4147825a      edit_format: Optional[str] = None\n119db373      tool_descriptions: Optional[str] = None\n4c7ffa93      use_system_role: bool\n6441aacc      prepend_system_text: str\ne3b0c442  \ne3b0c442  \nf268bc55  class CompactionConfig(BaseModel):\nafd132ce      \"\"\"Per-profile auto-compaction policy (Phase 3 D-11..D-17).\ne3b0c442  \n21a389de      Shipped in v3 as the first profile to carry the block; v2 (and v1) validate\n51f6e99e      without it (Optional[CompactionConfig] = None on ContextConfig). See\n79c7ccc5      CONTEXT.md D-11..D-17 + ``packages/emmy-context/`` for the runtime that\nbe2c3834      consumes this.\nc7fecba7      \"\"\"\ne3b0c442  \nf3bcdd66      model_config = ConfigDict(extra=\"forbid\", frozen=True)\nd5274f5c      soft_threshold_pct: float = Field(..., ge=0.0, le=1.0)\n3c57f7ee      preserve_recent_turns: int = Field(..., ge=0)\nc7eb9868      summarization_prompt_path: str = Field(..., min_length=1)\n4e4ff67c      preserve_tool_results: Literal[\"error_only\", \"none\", \"all\"] = \"error_only\"\ne3b0c442  \ne3b0c442  \n118a7c00  class MemoryConfig(BaseModel):\n2e84d1a2      \"\"\"Per-profile filesystem-memory tool config (Phase 04.4 plan 03).\ne3b0c442  \n878c7897      See `.planning/pre-phase/04.4-memory-compaction/MEMORY-TOOL-SPEC.md` §3.2\n8666babb      for design + defaults rationale. The runtime tool lives at\n66b35316      `packages/emmy-tools/src/memory/`; this schema is the only validated\n1ff6bb3f      contract between profile bundles and that runtime.\ne3b0c442  \nf6d03ed0      Fields:\n2abd17cf        - enabled: master switch. False → tool not registered; description omitted.\n51c4f677        - project_root: relative-to-cwd dir for /memories/project/...; null = scope disabled.\nca7287da        - global_root: ~-prefixed or absolute dir for /memories/global/...; null = scope 