./.planning/phases/04.4-filesystem-memory-tool-append-only-prefix-compaction-polish-/runs/v1-adoption-roundB/task11.jsonl:41:{"ts":"2026-04-27T04:26:45.550Z","type":"message_end","message":{"role":"toolResult","toolCallId":"call_6ed7964349784e57b45a726e","toolName":"read","content":[{"type":"text","text":"{\"path\":\"/data/projects/emmy/packages/emmy-provider/src/before-request-hook.ts\",\"binary\":false,\"lines\":\"f4fccf41  // packages/emmy-provider/src/before-request-hook.ts\\na2c23396  //\\n957442c8  // Plan 03-01 Task 2 (GREEN) — the pi 0.68 `before_provider_request`\\n98e972d4  // payload mutator. One concentrated place for the five live injections\\nf367dc20  // that Phase 3 Track B makes authoritative on every wire request:\\na2c23396  //\\n107bfd1f  //   (a) D-02a: chat_template_kwargs.enable_thinking:false at request level\\n2f10297e  //       — this is the PROPER fix that obsoletes the a17f4a9 `<think>`-strip\\n99c450a4  //       stopgap. vLLM's Qwen3.6 chat template reads enable_thinking and\\nfc8919a8  //       generates NO `<think>` prefix when it's false.\\na2c23396  //\\n9082f1c9  //   (b) D-02b: reactive grammar injection — when the retry-state for the\\n068e4ed8  //       request's AbortSignal says wantsGrammar=true (Phase 2 D-11 retry\\nedad8173  //       leg), this injects extra_body.guided_decoding.grammar_str from the\\nc5f34da3  //       profile's Lark file. Grammar config {path,mode} is the nested shape\\n85939b2a  //       (D-11 lock); mode=\\\"disabled\\\" suppresses injection even on retry\\n678ec0dd  //       (Plan 02-08 SC-3 no-grammar baseline).\\na2c23396  //\\n75acb813  //   (c) D-02c + D-04: the assembled 3-layer emmy prompt OVERWRITES pi's\\ne5aa1c63  //       templated system message at wire time. pi 0.68 builds its own\\n4867f587  //       system message from skills/resources; Emmy's prompt is the\\nc67e3d2b  //       CONTEXT-04 locked-order layering (system.md + AGENTS.md + tool_defs\\n73e50753  //       + user) whose SHA-256 is the HARNESS-06 audit identifier. The\\n427f1ca5  //       overwrite happens HERE — not at session boot — so every chat call\\n5d8e9b7e  //       on the live path carries the emmy-authoritative system prompt.\\na2c23396  //\\nad5b20c4  // SP_OK canary guard (RESEARCH Pitfall #7 / 03-CONTEXT T-03-01-02):\\n7e019a0f  //   If payload.emmy.is_sp_ok_canary === true, the hook is a pass-through.\\na0e3993b  //   The canary fires BEFORE buildRealPiRuntime so this branch should never\\ndb62291f  //   fire in practice — belt-and-suspenders against future wiring mistakes\\nb8bf0b32  //   that might route the canary through pi's stream.\\ne3b0c442  \\n7571c723  import { readFileSync } from \\\"node:fs\\\";\\nf84a38b0  import { join } from \\\"node:path\\\";\\n25b876df  import type { RetryState } from \\\"./grammar-retry\\\";\\n9a2839b6  import type { ProfileSnapshot, VariantSnapshot } from \\\"./types\\\";\\ne3b0c442  \\ndd30a96c  export type { RetryState };\\ne3b0c442  \\n06ca06b4  export interface BeforeProviderRequestPayload {\\n139f1edd  \\tmodel: string;\\n33cc29b5  \\tmessages: Array<{ role: string; content: unknown }>;\\nd76af79c  \\textra_body?: Record<string, unknown>;\\n0f11457c  \\tchat_template_kwargs?: Record<string, unknown>;\\ne4f56832  \\t// Phase 4 HARNESS-08 — variant-level sampling fields applied when a\\n1468f9ec  \\t// variantSnapshot is present. Their absence (undefined) means the wire\\n0656e1d4  \\t// layer or profile layer downstream is responsible for sampling\\nea08df8b  \\t// defaults; presence is a per-turn override.\\nd42996ec  \\ttemperature?: number;\\nf04fe480  \\ttop_p?: number;\\n7ff010ce  \\ttop_k?: number;\\nb770ed8d  \\tmax_tokens?: number;\\n10fccfaf  \\t/**\\nfecf0d18  \\t * Emmy-private payload namespace. Used today for the SP_OK canary\\n60e64dd5  \\t * pass-through flag; future fields (turn_id correlation, trace context)\\n1df88522  \\t * live here so they never collide with vLLM or OpenAI-standard fields.\\nf48539e2  \\t */\\n1d8f6353  \\temmy?: { is_sp_ok_canary?: boolean };\\nd10b36aa  }\\ne3b0c442  \\n2c6b4a45  export interface AssembledPromptSnapshot {\\n41fd265e  \\ttext: string;\\n9a5abbeb  \\tsha256: string;\\nd10b36aa  }\\ne3b0c442  \\n3487ef8c  export function handleBeforeProviderRequest(args: {\\na0739ee1  \\tpayload: BeforeProviderRequestPayload;\\n552828f4  \\tprofile: ProfileSnapshot;\\nca261bed  \\tassembledPrompt: AssembledPromptSnapshot;\\ne349cc0c  \\tretryState: RetryState | null;\\nd94758c6  \\t// Phase 4 Plan 04-04 (HARNESS-08) — per-turn variant snapshot. When\\nd9d6e8c3  \\t// present, its harness.sampling_defaults / chat_template_kwargs override\\nbb239c04  \\t// the base profile's values. When absent (existing callers + Phase 3\\nedd4ba9b  \\t// wiring), the hook's behavior is unchanged.\\nc97d88f9  \\tvariantSnapshot?: VariantSnapshot;\\n6d968387  }): void {\\n9bd5a50b  \\tconst { payload, profile, assembledPrompt, retryState, variantSnapshot } = args;\\ne3b0c442  \\n9fd2df0d  \\t// SP_OK canary guard — never mutate the canary's payload. The canary runs\\nb84d50f9  \\t// BEFORE pi's extension runtime exists, so this branch is defensive only.\\nf3c17948  \\tif (payload.emmy?.is_sp_ok_canary === true) return;\\ne3b0c442  \\nca5a7dd5  \\t// (pre) Plan 04-03 follow-up (2026-04-24): after /profile swap, pi's\\ndadac806  \\t// ModelRegistry still carries the boot-time served_model_name. vLLM\\n7ea6db3c  \\t// rejects with 404 (\\\"model X does not exist\\\") because the engine now\\n42548bca  \\t// answers under the NEW served_model_name. Overwrite payload.model with\\naa06fb9b  \\t// the currently-loaded profile's served_model_name on every request —\\n5ac8ccf3  \\t// idempotent pre-swap (same string), corrective post-swap.\\n86da8f51  \\tpayload.model = profile.serving.engine.served_model_name;\\ne3b0c442  \\n1cad510d  \\t// (a) D-02a: enable_thinking:false at request level. Removes a17f4a9.\\n7f76fa32  \\tpayload.chat_template_kwargs = {\\n0fee95c1  \\t\\t...(payload.chat_te