6e28  \\tref: ProfileRef;\\n46c4206e  \\t// Subset of serving.yaml consumed by the provider. Read once per session.\\ne870b69a  \\tserving: {\\n9453222e  \\t\\tengine: {\\nf890d8ed  \\t\\t\\tserved_model_name: string;\\nd70ee21b  \\t\\t\\tmax_model_len: number; // REQUIRED per W4 fix; downstream honest-max-model-len tests depend on it.\\n4769d519  \\t\\t};\\n8755a880  \\t\\tsampling_defaults: {\\n6150f803  \\t\\t\\ttemperature: number;\\n0c375baf  \\t\\t\\ttop_p: number;\\n2d0d1778  \\t\\t\\ttop_k?: number;\\n2acf9a0f  \\t\\t\\trepetition_penalty?: number;\\ndf74abda  \\t\\t\\tmax_tokens: number;\\n517cc359  \\t\\t\\tstop?: string[];\\n4769d519  \\t\\t};\\naa70df51  \\t\\tquirks: {\\naf867257  \\t\\t\\tstrip_thinking_tags: boolean;\\na0760ddb  \\t\\t\\tpromote_reasoning_to_content: boolean;\\n776d3dfd  \\t\\t\\tbuffer_tool_streams: boolean;\\n281bb417  \\t\\t\\t// Optional extension: extra fields to strip from every response message.\\n8ecbc8b6  \\t\\t\\tstrip_fields?: string[];\\n4769d519  \\t\\t};\\nd5130ff6  \\t};\\n79489925  \\t// Subset of harness.yaml consumed by the provider.\\n143c59a7  \\tharness: {\\n09a2514f  \\t\\ttools: {\\nd288111f  \\t\\t\\tformat: \\\"openai\\\" | \\\"hermes\\\";\\n31900827  \\t\\t\\t// D-11 LOCK: nested shape { path, mode }. NEVER flatten to a string.\\ne226b3b1  \\t\\t\\t// null means \\\"no grammar configured\\\" — retry path fails loud with `no_grammar_configured`.\\n4e165572  \\t\\t\\tgrammar: GrammarConfig | null;\\n9d26116e  \\t\\t\\tper_tool_sampling: Record<\\n37aaba0d  \\t\\t\\t\\tstring,\\n17bd5216  \\t\\t\\t\\tPartial<{\\nfb8c2286  \\t\\t\\t\\t\\ttemperature: number;\\n436fb9eb  \\t\\t\\t\\t\\ttop_p: number;\\n8e123059  \\t\\t\\t\\t\\tmax_tokens: number;\\n24110fd2  \\t\\t\\t\\t}>\\nf16b7ac6  \\t\\t\\t>;\\ne4262231  \\t\\t\\t/**\\nd0ca8f2c  \\t\\t\\t * Plan 03-06 (UX-03 / D-26 + D-27): per-profile web_fetch hostname\\nd7d9fa43  \\t\\t\\t * allowlist. When absent (Phase 2 v2 baseline) or empty, web_fetch\\n31148b1a  \\t\\t