mar` is populated ONLY on the reactive\\n6b50f7a1  //   retry (D-11); never on the first call.\\na2c23396  //\\nfd7c1338  // Timeouts: default 120s matches `replay.py`; the SP_OK canary caller passes\\n6d441ba5  // 60000ms per `sp_ok.py`.\\ne3b0c442  \\n4605332f  import { NetworkError } from \\\"./errors\\\";\\n75a9308f  import type { ChatRequest, ChatResponse } from \\\"./types\\\";\\ne3b0c442  \\n9b4b8c14  export async function postChat(\\n3fc75565  \\tbaseUrl: string,\\n93cd6f2b  \\tpayload: ChatRequest,\\ndb18feff  \\topts: { timeoutMs?: number } = {},\\nf7bbd09b  ): Promise<ChatResponse> {\\neb45b7fc  \\tconst url = `${baseUrl.replace(/\\\\/$/, \\\"\\\")}/v1/chat/completions`;\\n9d583544  \\tconst timeoutMs = opts.timeoutMs ?? 120_000;\\n99ca39aa  \\tconst controller = new AbortController();\\n8f9a52ee  \\tconst timer = setTimeout(() => {\\nce1d447b  \\t\\t// AbortController.abort(reason) exists on modern runtimes; fall back gracefully.\\n131bbee0  \\t\\ttry {\\n66455ff5  \\t\\t\\t(controller as AbortController & { abort: (reason?: unknown) => void }).abort(\\ne2d0e426  \\t\\t\\t\\tnew Error(\\\"timeout\\\"),\\ncdf704fc  \\t\\t\\t);\\n3dbe4bd7  \\t\\t} catch (_e) {\\n346c162f  \\t\\t\\tcontroller.abort();\\n3713bbfd  \\t\\t}\\nb8aa8589  \\t}, timeoutMs);\\ndebaf31e  \\ttry {\\n14a431d0  \\t\\tconst resp = await fetch(url, {\\n65680448  \\t\\t\\tmethod: \\\"POST\\\",\\na650aae9  \\t\\t\\theaders: { \\\"content-type\\\": \\\"application/json\\\" },\\n2ae16f29  \\t\\t\\tbody: JSON.stringify(payload),\\n03c0f11f  \\t\\t\\tsignal: controller.signal,\\n206aa438  \\t\\t});\\n0e23e21f  \\t\\tif (!resp.ok) {\\n7a831597  \\t\\t\\tconst text = await resp.text().catch(() => \\\"(unreadable body)\\\");\\ndbdbdd1f  \\t\\t\\tthrow new NetworkError(url, resp.status, text.slice(0, 512));\\n3713bbfd  \\t\\t}\\n0bdce2cf  \\t\\treturn (await resp.json()) as ChatResponse;\\n2959c032  \\t} catch (e: unknown) {\\n52447d86  \\t\\tif (e instanceof NetworkError) throw e;\\n8ac2d31a  \\t\\tif (\\n061cade0  \\t\\t\\te instanceof Error &&\\n1ef68a6f  \\t\\t\\t(e.name === \\\"AbortError\\\" ||\\n49987521  \\t\\t\\t\\te.name === \\\"TimeoutError\\\" ||\\n1d9ccaff  \\t\\t\\t\\t/timeout/i.test(e.message))\\n883ac9b7  \\t\\t) {\\n576acc81  \\t\\t\\tthrow new NetworkError(url, null, `timeout after ${timeoutMs}ms`);\\n3713bbfd  \\t\\t}\\n29fdc5c9  \\t\\tthrow new NetworkError(\\nb62303bf  \\t\\t\\turl,\\n035aecc0  \\t\\t\\tnull,\\n4cb9d120  \\t\\t\\te instanceof Error ? e.message : String(e),\\n80e5ba03  \\t\\t);\\nbc9be798  \\t} finally {\\ne1f2f5bf  \\t\\tclearTimeout(timer);\\na32a3bb7  \\t}\\nd10b36aa  }\\n\",\"line_count\":65}"}],"details":{"path":"/data/projects/emmy/packages/emmy-provider/src/http.ts","binary":false,"lines":"461f6ca8  // packages/emmy-provider/src/http.ts\na2c23396  //\n1187682f  // Thin fetch wrapper around vLLM's OpenAI-compat `/v1/chat/completions`.\n9d37ea3b  // Wire shape mirrors the Phase 1 Python canaries verbatim (see\na248707e  // `emmy_serve/canary/replay.py` and `emmy_serve/canary/sp_ok.py`):\n4be284b5  // - `chat_template_kwargs` lives at the TOP LEVEL of the body (vLLM ignores\n849dfb7e  //   the OpenAI-SDK-only `extra_body` concept as a server field).\ndf364786  // - `extra_body.guided_decoding.grammar` is populated ONLY on the reactive\n6b50f7a1  //   retry (D-11); never on the first call.\na2c23396  //\nfd7c1338  // Timeouts: default 120s matches `replay.py`; the SP_OK canary caller passes\n6d441ba5  // 60000ms per `sp_ok.py`.\ne3b0c442  \n4605332f  import { NetworkError } from \"./errors\";\n75a9308f  import type { ChatRequest, ChatResponse } from \"./types\";\ne3b0c442  \n9b4b8c14  export async function postChat(\n3fc75565  \tbaseUrl: string,\n93cd6f2b  \tpayload: ChatRequest,\ndb18feff  \topts: { timeoutMs?: number } = {},\nf7bbd09b  ): Promise<ChatResponse> {\neb45b7fc  \tconst url = `${baseUrl.replace(/\\/$/, \"\")}/v1/chat/completions`;\n9d583544  \tconst timeoutMs = opts.timeoutMs ?? 120_000;\n99ca39aa  \tconst